import { Box, LinearProgress, TableCell } from "@mui/material";
import dayjs from "dayjs";
import { memo } from "react";

import { useTT } from "../../useTT.ts";
import { useIsColumnSelected } from "../SelectionContext.tsx";
import { useTimePeriodControls } from "../TimePeriodContext.tsx";
import { formatCashflowAmount } from "../utils/index.ts";
import type { CashflowTableCellProps } from "./types/index.ts";

/**
 * Reusable table cell component for the cashflow table.
 *
 * Performance: Memoized to prevent unnecessary re-renders. With 140+ cells
 * (7 periods x 20 categories), React.memo combined with useIsColumnSelected
 * ensures only cells whose highlight status changes re-render (typically ~14
 * cells during column highlighting: 7 cells losing highlight + 7 gaining it).
 */
function CashflowTableCellComponent({
  value,
  columnIndex,
  dateFrom,
  isBold = false,
  progressPercentage,
  colorMode,
  onClick,
}: CashflowTableCellProps) {
  const { language } = useTT();
  const isHighlighted = useIsColumnSelected(columnIndex);
  const { setPeriod } = useTimePeriodControls();

  const handleClick = onClick ?? (() => setPeriod(dayjs(dateFrom)));

  return (
    <TableCell
      onClick={handleClick}
      aria-selected={isHighlighted}
      sx={{
        textAlign: "right",
        cursor: "pointer",
        backgroundColor: "background.paper",
        borderBottom: isHighlighted ? "none" : undefined,
        borderRight: 1,
        borderRightColor: isHighlighted
          ? "custom.borderSecondary"
          : "background.paper",
        borderLeft: 1,
        borderLeftColor: isHighlighted
          ? "custom.borderSecondary"
          : "background.paper",
        fontWeight: isBold ? 600 : 400,
        color: getValueColor(colorMode, value),
        boxSizing: "border-box",
      }}
    >
      <Box>
        {formatCashflowAmount(value, language)}
        {progressPercentage !== undefined && (
          <LinearProgress
            variant="determinate"
            value={progressPercentage}
            sx={{
              mt: 0.5,
              height: 4,
              borderRadius: 1,
              backgroundColor: "action.hover",
              "& .MuiLinearProgress-bar": {
                backgroundColor:
                  progressPercentage > 100 ? "warning.main" : "primary.main",
              },
            }}
          />
        )}
